using Moq;
using Moq.Protected;
using OpenWeatherMap.Sdk.Models;
using System.Net;

namespace OpenWeatherMap.Sdk.Tests;

public class OpenWeatherMapClientTests
{
    [Fact]
    public async Task GetGeoCoordinatesAsync_should_return_correct_values()
    {
        var name = "Boutersem";
        var latitude = "50.847346099999996";
        var longitude = "4.83361780525583";
        var countryCode = "BE";
        var state = "Flemish Brabant";
        var languageCode = "nl";
        var languageValue = "Boutersem";

        var handler = new Mock<HttpMessageHandler>();
        
        ConfigureHandlerToReturnStringContent(handler, $"[{{\"name\":\"{name}\",\"local_names\":{{\"{languageCode}\":\"{languageValue}\"}},\"lat\":{latitude},\"lon\":{longitude},\"country\":\"{countryCode}\",\"state\":\"{state}\"}}]");

        var httpClient = new HttpClient(handler.Object);

        var openWeatherMapClient = new OpenWeatherMapClient(httpClient, "testkey");

        var geoCoordinates = (await openWeatherMapClient.GetGeoCoordinatesAsync("Boutersem")).ToArray();

        Assert.NotNull(geoCoordinates);
        Assert.True(geoCoordinates.Length == 1);
        var coordinates = geoCoordinates[0];
        Assert.Equal(name, coordinates.CityName);
        Assert.Equal(double.Parse(latitude.Replace('.',',')), coordinates.Latitude);
        Assert.Equal(double.Parse(longitude.Replace('.', ',')), coordinates.Longitude);
        Assert.Equal(countryCode, coordinates.CountryCode);
        Assert.Equal(state, coordinates.State);
        Assert.Equal(languageValue, coordinates.LocalNames[languageCode]);
    }

    [Fact]
    public async Task GetCurrentWeather_should_return_correct_values()
    {
        var latitude = 50.847346099999996;
        var longitude = 4.83361780525583;
        
        var handler = new Mock<HttpMessageHandler>();

        ConfigureHandlerToReturnStringContent(handler, "{\"coord\":{\"lon\":4.8336,\"lat\":50.8473},\"weather\":[{\"id\":803,\"main\":\"Clouds\",\"description\":\"broken clouds\",\"icon\":\"04d\"}],\"base\":\"stations\",\"main\":{\"temp\":287.92,\"feels_like\":287.33,\"temp_min\":287.23,\"temp_max\":288.92,\"pressure\":1006,\"humidity\":72},\"visibility\":10000,\"wind\":{\"speed\":7.2,\"deg\":190},\"clouds\":{\"all\":75},\"dt\":1667910978,\"sys\":{\"type\":1,\"id\":1223,\"country\":\"BE\",\"sunrise\":1667889850,\"sunset\":1667923481},\"timezone\":3600,\"id\":2795446,\"name\":\"Hoogbutsel\",\"cod\":200}");

        var httpClient = new HttpClient(handler.Object);

        var openWeatherMapClient = new OpenWeatherMapClient(httpClient, "testkey");

        var currentWeather = await openWeatherMapClient.GetCurrentWeatherAsync(latitude, longitude);

        Assert.NotNull(currentWeather);
        Assert.Equal("Hoogbutsel", currentWeather.CityName);
        Assert.Equal(latitude, currentWeather.Latitude, 3);
        Assert.Equal("04d", currentWeather.WeatherIcon);
        Assert.Equal(287.92, currentWeather.Temperature);
        Assert.Equal(72, currentWeather.Humidity);
        Assert.Equal(10000, currentWeather.Visibility);
        Assert.Equal(7.2, currentWeather.WindSpeed);
        Assert.Equal(75, currentWeather.Cloudiness);
        Assert.Equal("BE", currentWeather.CountryCode);
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1667910978).DateTime, currentWeather.UpdatedAt);
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1667889850).DateTime, currentWeather.Sunrise);
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1667923481).DateTime, currentWeather.Sunset);
    }

