        var httpClient = new HttpClient(handler.Object);

        var openWeatherMapClient = new OpenWeatherMapClient(httpClient, "testkey");

        var weatherForecast = await openWeatherMapClient.GetFiveDaysThreeHoursForecastAsync(latitude, longitude);

        Assert.NotNull(weatherForecast);
        Assert.Equal("Hoogbutsel", weatherForecast.CityName);
        Assert.Equal(latitude, weatherForecast.Latitude, 3);
        Assert.Equal("BE", weatherForecast.CountryCode);
        Assert.Equal(3600, weatherForecast.TimeZone);
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1667889850).DateTime, weatherForecast.Sunrise);
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1667923481).DateTime, weatherForecast.Sunset);

        Assert.Equal(40, weatherForecast.HourlyForecast.Count());
        var firstForecast = weatherForecast.HourlyForecast.First();
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1667919600).DateTime, firstForecast.ForecastDateTime);
        Assert.Equal("04d", firstForecast.WeatherIcon);
        Assert.Equal(288.14, firstForecast.Temperature);
        Assert.Equal(68, firstForecast.Humidity);
        Assert.Equal(10000, firstForecast.Visibility);
        Assert.Equal(8.49, firstForecast.WindSpeed);
        Assert.Equal(15.68, firstForecast.WindGust);
        Assert.Equal(83, firstForecast.Cloudiness);
        Assert.Equal(0, firstForecast.PrecipitationProbability);
        Assert.Equal(WeatherPartOfDay.Day, firstForecast.PartOfDay);
        var lastForecast = weatherForecast.HourlyForecast.Last();
        Assert.Equal(DateTimeOffset.FromUnixTimeSeconds(1668340800).DateTime, lastForecast.ForecastDateTime);
        Assert.Equal("01d", lastForecast.WeatherIcon);
        Assert.Equal(290.18, lastForecast.Temperature);
        Assert.Equal(57, lastForecast.Humidity);
        Assert.Equal(10000, lastForecast.Visibility);
        Assert.Equal(4.23, lastForecast.WindSpeed);
        Assert.Equal(6.37, lastForecast.WindGust);
        Assert.Equal(8, lastForecast.Cloudiness);
        Assert.Equal(0, lastForecast.PrecipitationProbability);
        Assert.Equal(WeatherPartOfDay.Day, lastForecast.PartOfDay);
    }

