,\"main\":{\"temp\":274.66,\"feels_like\":274.66,\"temp_min\":274.66,\"temp_max\":274.66,\"pressure\":1031,\"sea_level\":1031,\"grnd_level\":1025,\"humidity\":90,\"temp_kf\":0},\"weather\":[{\"id\":800,\"main\":\"Clear\",\"description\":\"clear sky\",\"icon\":\"01n\"}],\"clouds\":{\"all\":6},\"wind\":{\"speed\":0.99,\"deg\":40,\"gust\":1},\"visibility\":10000,\"pop\":0,\"sys\":{\"pod\":\"n\"},\"dt_txt\":\"2022-11-14 15:00:00\"}],\"city\":{\"id\":5809844,\"name\":\"Seattle\",\"coord\":{\"lat\":47.6038,\"lon\":-122.3301},\"country\":\"US\",\"population\":608660,\"timezone\":-28800,\"sunrise\":1668006342,\"sunset\":1668040842}}");

