        var openWeatherMapClient = new OpenWeatherMapClient(httpClient, "testkey");

        var weatherForecast = await openWeatherMapClient.GetFiveDaysThreeHoursForecastAsync(latitude, 4.83361780525583);

        var dailyForecast = openWeatherMapClient.GetFiveDaysDailyForecast(weatherForecast);

        Assert.NotNull(dailyForecast);
        Assert.Equal(6, dailyForecast.DailyForecast.Count());
        Assert.Equal("Hoogbutsel", dailyForecast.CityName);
        Assert.Equal(latitude, dailyForecast.Latitude, 3);
